   565→func getSecretReferences(serviceAccount *v1.ServiceAccount) sets.String {
   566→	references := sets.NewString()
   567→	for _, secret := range serviceAccount.Secrets {
   568→		references.Insert(secret.Name)
   569→	}
   570→	return references
   571→}
