   270→	retry := false
   271→	defer func() {
   272→		retryOrForget(logger, e.syncSecretQueue, key, retry, e.maxRetries)
   273→	}()
   274→
   275→	secretInfo, err := parseSecretQueueKey(key)
   276→	if err != nil {
   277→		logger.Error(err, "Parsing secret queue key")
   278→		return
