   296→	default:
   297→		// Ensure service account exists
   298→		sa, saErr := e.getServiceAccount(secretInfo.namespace, secretInfo.saName, secretInfo.saUID, true)
   299→		switch {
   300→		case saErr != nil:
   301→			logger.Error(saErr, "Getting service account")
   302→			retry = true
   303→		case sa == nil:
