   340→func (e *TokensController) deleteToken(ns, name string, uid types.UID) ( /*retry*/ bool, error) {
   341→	var opts metav1.DeleteOptions
   342→	if len(uid) > 0 {
   343→		opts.Preconditions = &metav1.Preconditions{UID: &uid}
   344→	}
   345→	err := e.client.CoreV1().Secrets(ns).Delete(context.TODO(), name, opts)
   346→	// NotFound doesn't need a retry (it's already been deleted)
   347→	// Conflict doesn't need a retry (the UID precondition failed)
   348→	if err == nil || apierrors.IsNotFound(err) || apierrors.IsConflict(err) {
   349→		return false, nil
   350→	}
   351→	// Retry for any other error
   352→	return true, err
   353→}
   354→
   355→func (e *TokensController) secretUpdateNeeded(secret *v1.Secret) (bool, bool, bool) {
   356→	caData := secret.Data[v1.ServiceAccountRootCAKey]
   357→	needsCA := len(e.rootCA) > 0 && !bytes.Equal(caData, e.rootCA)
   358→
   359→	needsNamespace := len(secret.Data[v1.ServiceAccountNamespaceKey]) == 0
   360→
   361→	tokenData := secret.Data[v1.ServiceAccountTokenKey]
   362→	needsToken := len(tokenData) == 0
   363→
   364→	return needsCA, needsNamespace, needsToken
   365→}
   366→
   367→// generateTokenIfNeeded populates the token data for the given Secret if not already set
   368→func (e *TokensController) generateTokenIfNeeded(logger klog.Logger, serviceAccount *v1.ServiceAccount, cachedSecret *v1.Secret) ( /* retry */ bool, error) {
   369→	// Check the cached secret to see if changes are needed
   370→	if needsCA, needsNamespace, needsToken := e.secretUpdateNeeded(cachedSecret); !needsCA && !needsToken && !needsNamespace {
   371→		return false, nil
   372→	}
   373→
   374→	// We don't want to update the cache's copy of the secret
   375→	// so add the token to a freshly retrieved copy of the secret
   376→	secrets := e.client.CoreV1().Secrets(cachedSecret.Namespace)
   377→	liveSecret, err := secrets.Get(context.TODO(), cachedSecret.Name, metav1.GetOptions{})
   378→	if err != nil {
   379→		// Retry for any error other than a NotFound
   380→		return !apierrors.IsNotFound(err), err
   381→	}
   382→	if liveSecret.ResourceVersion != cachedSecret.ResourceVersion {
   383→		// our view of the secret is not up to date
   384→		// we'll get notified of an update event later and get to try again
   385→		logger.V(2).Info("Secret is not up to date, skipping token population", "secret", klog.KRef(liveSecret.Namespace, liveSecret.Name))
   386→		return false, nil
   387→	}
   388→
   389→	needsCA, needsNamespace, needsToken := e.secretUpdateNeeded(liveSecret)
   390→	if !needsCA && !needsToken && !needsNamespace {
   391→		return false, nil
   392→	}
   393→
   394→	if liveSecret.Annotations == nil {
   395→		liveSecret.Annotations = map[string]string{}
   396→	}
   397→	if liveSecret.Data == nil {
   398→		liveSecret.Data = map[string][]byte{}
   399→	}
   400→
   401→	// Set the CA
   402→	if needsCA {
   403→		liveSecret.Data[v1.ServiceAccountRootCAKey] = e.rootCA
   404→	}
   405→	// Set the namespace
   406→	if needsNamespace {
   407→		liveSecret.Data[v1.ServiceAccountNamespaceKey] = []byte(liveSecret.Namespace)
   408→	}
   409→
   410→	// Generate the token
   411→	if needsToken {
   412→		c, pc := serviceaccount.LegacyClaims(*serviceAccount, *liveSecret)
   413→		// TODO: need to plumb context if using external signer ever becomes a posibility.
   414→		token, err := e.token.GenerateToken(context.TODO(), c, pc)
   415→		if err != nil {
   416→			return false, err
   417→		}
   418→		liveSecret.Data[v1.ServiceAccountTokenKey] = []byte(token)
   419→	}
   420→
   421→	// Set annotations
   422→	liveSecret.Annotations[v1.ServiceAccountNameKey] = serviceAccount.Name
   423→	liveSecret.Annotations[v1.ServiceAccountUIDKey] = string(serviceAccount.UID)
   424→
   425→	// Save the secret
   426→	_, err = secrets.Update(context.TODO(), liveSecret, metav1.UpdateOptions{})
   427→	if apierrors.IsConflict(err) || apierrors.IsNotFound(err) {
   428→		// if we got a Conflict error, the secret was updated by someone else, and we'll get an update notification later
   429→		// if we got a NotFound error, the secret no longer exists, and we don't need to populate a token
   430→		return false, nil
   431→	}
   432→	if err != nil {
   433→		return true, err
   434→	}
   435→	return false, nil
   436→}
   437→
   438→// removeSecretReference updates the given ServiceAccount to remove a reference to the given secretName if needed.
   439→func (e *TokensController) removeSecretReference(saNamespace string, saName string, saUID types.UID, secretName string) error {
   440→	// We don't want to update the cache's copy of the service account
   441→	// so remove the secret from a freshly retrieved copy of the service account
   442→	serviceAccounts := e.client.CoreV1().ServiceAccounts(saNamespace)
   443→	serviceAccount, err := serviceAccounts.Get(context.TODO(), saName, metav1.GetOptions{})
   444→	// Ignore NotFound errors when attempting to remove a reference
   445→	if apierrors.IsNotFound(err) {
   446→		return nil
   447→	}
   448→	if err != nil {
   449→		return err
   450→	}
   451→
   452→	// Short-circuit if the UID doesn't match
   453→	if len(saUID) > 0 && saUID != serviceAccount.UID {
   454→		return nil
   455→	}
   456→
   457→	// Short-circuit if the secret is no longer referenced
   458→	if !getSecretReferences(serviceAccount).Has(secretName) {
   459→		return nil
   460→	}
   461→
   462→	// Remove the secret
   463→	secrets := []v1.ObjectReference{}
   464→	for _, s := range serviceAccount.Secrets {
   465→		if s.Name != secretName {
   466→			secrets = append(secrets, s)
   467→		}
   468→	}
   469→	serviceAccount.Secrets = secrets
   470→	_, err = serviceAccounts.Update(context.TODO(), serviceAccount, metav1.UpdateOptions{})
   471→	// Ignore NotFound errors when attempting to remove a reference
   472→	if apierrors.IsNotFound(err) {
   473→		return nil
   474→	}
   475→	return err
   476→}
   477→
   478→func (e *TokensController) getServiceAccount(ns string, name string, uid types.UID, fetchOnCacheMiss bool) (*v1.ServiceAccount, error) {
   479→	// Look up in cache
   480→	sa, err := e.serviceAccounts.ServiceAccounts(ns).Get(name)
   481→	if err != nil && !apierrors.IsNotFound(err) {
   482→		return nil, err
   483→	}
   484→	if sa != nil {
   485→		// Ensure UID matches if given
   486→		if len(uid) == 0 || uid == sa.UID {
   487→			return sa, nil
   488→		}
   489→	}
   490→
   491→	if !fetchOnCacheMiss {
   492→		return nil, nil
   493→	}
   494→
   495→	// Live lookup
   496→	sa, err = e.client.CoreV1().ServiceAccounts(ns).Get(context.TODO(), name, metav1.GetOptions{})
   497→	if apierrors.IsNotFound(err) {
   498→		return nil, nil
   499→	}
   500→	if err != nil {
   501→		return nil, err
   502→	}
   503→	// Ensure UID matches if given
   504→	if len(uid) == 0 || uid == sa.UID {
   505→		return sa, nil
   506→	}
   507→	return nil, nil
   508→}
   509→
   510→func (e *TokensController) getSecret(ns string, name string, uid types.UID, fetchOnCacheMiss bool) (*v1.Secret, error) {
   511→	// Look up in cache
   512→	obj, exists, err := e.updatedSecrets.GetByKey(makeCacheKey(ns, name))
   513→	if err != nil {
   514→		return nil, err
   515→	}
   516→	if exists {
   517→		secret, ok := obj.(*v1.Secret)
   518→		if !ok {
   519→			return nil, fmt.Errorf("expected *v1.Secret, got %#v", secret)
   520→		}
   521→		// Ensure UID matches if given
   522→		if len(uid) == 0 || uid == secret.UID {
   523→			return secret, nil
   524→		}
   525→	}
   526→
   527→	if !fetchOnCacheMiss {
   528→		return nil, nil
   529→	}
   530→
   531→	// Live lookup
   532→	secret, err := e.client.CoreV1().Secrets(ns).Get(context.TODO(), name, metav1.GetOptions{})
   533→	if apierrors.IsNotFound(err) {
   534→		return nil, nil
   535→	}
   536→	if err != nil {
   537→		return nil, err
   538→	}
   539→	// Ensure UID matches if given
   540→	if len(uid) == 0 || uid == secret.UID {
   541→		return secret, nil
   542→	}
   543→	return nil, nil
   544→}
   545→
   546→// listTokenSecrets returns a list of all of the ServiceAccountToken secrets that
   547→// reference the given service account's name and uid
   548→func (e *TokensController) listTokenSecrets(serviceAccount *v1.ServiceAccount) ([]*v1.Secret, error) {
   549→	namespaceSecrets, err := e.updatedSecrets.ByIndex("namespace", serviceAccount.Namespace)
   550→	if err != nil {
   551→		return nil, err
   552→	}
   553→
   554→	items := []*v1.Secret{}
   555→	for _, obj := range namespaceSecrets {
   556→		secret := obj.(*v1.Secret)
   557→
   558→		if apiserverserviceaccount.IsServiceAccountToken(secret, serviceAccount) {
   559→			items = append(items, secret)
   560→		}
   561→	}
   562→	return items, nil
   563→}
   564→
   565→func getSecretReferences(serviceAccount *v1.ServiceAccount) sets.String {
   566→	references := sets.NewString()
   567→	for _, secret := range serviceAccount.Secrets {
   568→		references.Insert(secret.Name)
   569→	}
   570→	return references
   571→}
   572→
   573→// serviceAccountQueueKey holds information we need to sync a service account.
   574→// It contains enough information to look up the cached service account,
   575→// or delete owned tokens if the service account no longer exists.
   576→type serviceAccountQueueKey struct {
   577→	namespace string
   578→	name      string
   579→	uid       types.UID
   580→}
   581→
   582→func makeServiceAccountKey(sa *v1.ServiceAccount) serviceAccountQueueKey {
   583→	return serviceAccountQueueKey{
   584→		namespace: sa.Namespace,
   585→		name:      sa.Name,
   586→		uid:       sa.UID,
   587→	}
   588→}
   589→
   590→func parseServiceAccountKey(key interface{}) (serviceAccountQueueKey, error) {
   591→	queueKey, ok := key.(serviceAccountQueueKey)
   592→	if !ok || len(queueKey.namespace) == 0 || len(queueKey.name) == 0 || len(queueKey.uid) == 0 {
   593→		return serviceAccountQueueKey{}, fmt.Errorf("invalid serviceaccount key: %#v", key)
   594→	}
   595→	return queueKey, nil
   596→}
   597→
   598→// secretQueueKey holds information we need to sync a service account token secret.
   599→// It contains enough information to look up the cached service account,
   600→// or delete the secret reference if the secret no longer exists.
   601→type secretQueueKey struct {
   602→	namespace string
   603→	name      string
   604→	uid       types.UID
   605→	saName    string
   606→	// optional, will be blank when syncing tokens missing the service account uid annotation
   607→	saUID types.UID
   608→}
   609→
   610→func makeSecretQueueKey(secret *v1.Secret) secretQueueKey {
   611→	return secretQueueKey{
   612→		namespace: secret.Namespace,
   613→		name:      secret.Name,
   614→		uid:       secret.UID,
   615→		saName:    secret.Annotations[v1.ServiceAccountNameKey],
   616→		saUID:     types.UID(secret.Annotations[v1.ServiceAccountUIDKey]),
   617→	}
   618→}
   619→
   620→func parseSecretQueueKey(key interface{}) (secretQueueKey, error) {
   621→	queueKey, ok := key.(secretQueueKey)
   622→	if !ok || len(queueKey.namespace) == 0 || len(queueKey.name) == 0 || len(queueKey.uid) == 0 || len(queueKey.saName) == 0 {
   623→		return secretQueueKey{}, fmt.Errorf("invalid secret key: %#v", key)
   624→	}
   625→	return queueKey, nil
   626→}
   627→
   628→// produce the same key format as cache.MetaNamespaceKeyFunc
   629→func makeCacheKey(namespace, name string) string {
   630→	return namespace + "/" + name
   631→}
   632→

